/**
 * Mock data for Customers · Reviews.
 *
 * Four instruments:
 *  1. Rating × loyalty — bars (repeat rate) + line (avg LTV) by star rating
 *  2. Root cause — ranked negative-review causes by LTV-at-risk, mapped to the owning room
 *  3. Recovery — resolved-vs-unanswered split + lift in repeat rate when replied
 *  4. At-risk worklist — unanswered reviews ranked by LTV at stake
 *
 * USD currency per canonical rule.
 */

export interface RatingBar {
  stars: 1 | 2 | 3 | 4 | 5;
  count: number;
  /** % of customers with this rating who come back. */
  repeatPct: number;
  /** Avg lifetime value in USD. */
  ltv: number;
}

