export interface RecoveryCut {
  label: string;
  count: number;
  /** Repeat rate as %. */
  repeat: number;
  repeatTone: "green" | "red";
  /** Secondary metric, e.g. "4 hrs" or "11 days". */
  secondary: string;
  secondaryLabel: string;
  /** Money line — "$34K retained" / "$95K at risk". */
  money: string;
  moneyLabel: string;
  moneyTone: "green" | "red";
  accent: string;
}

