"use client";

import { useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { RatingLoyalty } from "@/components/charts/RatingLoyalty";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  RATING_BARS,
  ROOT_CAUSES,
  RECOVERY_CUTS,
  AT_RISK_REVIEWS,
  reviewsMetrics,
  reviewsAI,
} from "@/features/customers/api/customers-reviews-data";
import "./reviews.css";

const PERIOD_LABELS = ["Last 90 days", "Last 12 months", "All time"];

const SECTIONS = [
  { id: "s-rating", label: "Rating & loyalty" },
  { id: "s-cause", label: "Root cause" },
  { id: "s-recovery", label: "Recovery" },
  { id: "s-work", label: "At-risk reviews", count: 22 },
];

export default function ReviewsPage() {
  const [periodIdx, setPeriodIdx] = useState(0);
  const [activeSection, setActiveSection] = useState("s-rating");
  const { openBridge } = useBridge();

  const scrollTo = (id: string) => {
    setActiveSection(id);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  return (
    <div className="customers-reviews-page">
      <DeptHeader
        dept="customers"
        title="Reviews"
        meta={
          <>
            <span className="live">Live</span> · 500 reviews · scored against repeat rate &amp; LTV, not as a vanity number
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("customers")}
            >
              Recover at-risk → Bridge
            </button>
          </>
        }
      />
      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Average rating</div>
          <div className="metric-v">
            {reviewsMetrics.rating}
            <span className="star">★</span>
          </div>
          <div className="metric-yoy down">{reviewsMetrics.ratingDelta} <span className="yl">YoY</span></div>
        </div>
        <div className="metric">
          <div className="metric-l">Reviews · 90d</div>
          <div className="metric-v">{reviewsMetrics.count}</div>
          <div className="metric-yoy up">{reviewsMetrics.countDelta} <span className="yl">vs LY</span></div>
        </div>
        <div className="metric">
          <div className="metric-l">5★ repeat rate</div>
          <div className="metric-v green">{reviewsMetrics.fiveStarRepeat}</div>
          <div className="metric-yoy flat">{reviewsMetrics.fiveStarDelta}</div>
        </div>
        <div className="metric">
          <div className="metric-l">1–2★ repeat rate</div>
          <div className="metric-v red">{reviewsMetrics.lowStarRepeat}</div>
          <div className="metric-yoy down">{reviewsMetrics.lowStarDelta} <span className="yl">YoY</span></div>
        </div>
        <div className="metric">
          <div className="metric-l">LTV at risk · unhappy</div>
          <div className="metric-v red">{reviewsMetrics.ltvAtRisk}</div>
          <div className="metric-yoy down">{reviewsMetrics.ltvAtRiskDelta} <span className="yl">YoY</span></div>
        </div>
      </div>

      <AIStrip label={reviewsAI.label} meta={reviewsAI.meta} cards={reviewsAI.cards} />

      <div className="secnav">
        {SECTIONS.map((s) => (
          <button
            key={s.id}
            type="button"
            className={activeSection === s.id ? "active" : ""}
            onClick={() => scrollTo(s.id)}
          >
            {s.label}
            {s.count !== undefined && <span className="ct">{s.count}</span>}
          </button>
        ))}
      </div>

      {/* 1 — Rating × loyalty */}
      <section className="section" id="s-rating">
        <SectionLabel>
          <span className="n">1</span> Rating &amp; loyalty <span className="sl-note">— does a star rating translate into customers who come back?</span>
        </SectionLabel>
        <div className="icard">
          <div className="ic-head">
            <div className="ic-title">Repeat rate and lifetime value by star rating</div>
            <div className="ic-sub">Bars = repeat rate · line = average LTV · the gradient is the point</div>
          </div>
          <RatingLoyalty data={RATING_BARS} />
          <div className="dc-read warn">
            A rating isn&rsquo;t sentiment — it&rsquo;s a forecast of behaviour. A 5★ customer comes back more than half the time and is worth <b>$4,200</b>; a 1★ customer comes back 6% of the time and is worth <b>$480</b>. Both repeat rate and lifetime value collapse together as the rating falls. The good news is most reviews sit on the right; the cost is concentrated in a small, expensive tail on the left.
          </div>
        </div>
      </section>

      {/* 2 — Root cause */}
      <section className="section" id="s-cause">
        <SectionLabel>
          <span className="n">2</span> Root cause <span className="sl-note">— why the unhappy ones are unhappy, traced to the process behind it</span>
        </SectionLabel>
        <div className="gc-intro">
          30 negative reviews (1–3★) · <b>$130K LTV at risk</b> · ranked by value at stake, each mapped to the room that owns the fix
        </div>
        <div className="row-card">
          <RootCauseList />
        </div>
        <div className="dc-read warn">
          Most of the damage is operational, not emotional. <b>Six in ten</b> negative reviews are late deliveries — a dispatch problem, fixable in Operations, not by answering reviews more nicely. Treating reviews as a customer-service queue misses this; treating them as a defect log points you straight at the process to fix.
        </div>
      </section>

      {/* 3 — Recovery */}
      <section className="section" id="s-recovery">
        <SectionLabel>
          <span className="n">3</span> Recovery <span className="sl-note">— does answering an unhappy customer actually win them back?</span>
        </SectionLabel>
        <div className="cut">
          {RECOVERY_CUTS.map((cut) => (
            <div
              key={cut.label}
              className="cut-card"
              style={{ ["--cc" as string]: cut.accent } as React.CSSProperties}
            >
              <div className="cl">{cut.label}</div>
              <div className="cut-row">
                <div className="cut-m">
                  <div className="ml">Repeat rate</div>
                  <div className={`mv ${cut.repeatTone}`}>{cut.repeat}%</div>
                </div>
                <div className="cut-m">
                  <div className="ml">{cut.secondaryLabel}</div>
                  <div className="mv">{cut.secondary}</div>
                </div>
                <div className="cut-m">
                  <div className="ml">{cut.moneyLabel}</div>
                  <div className={`mv ${cut.moneyTone}`}>{cut.money}</div>
                </div>
              </div>
            </div>
          ))}
        </div>
        <div className="dc-read ok">
          Answering works: a resolved complaint repeats at <b>41%</b> against <b>8%</b> unanswered — five times the recovery. Right now 22 sit unanswered for an average of 11 days, with about <b>$95K</b> of lifetime value attached. Every day one stays open, the chance of winning that customer back drops. This is the cheapest recovery lever you have.
        </div>
      </section>

      {/* 4 — Worklist */}
      <section className="section" id="s-work">
        <SectionLabel>
          <span className="n">4</span> At-risk reviews <span className="sl-note">— who to answer first, ranked by the lifetime value on the line</span>
        </SectionLabel>
        <div className="gc-intro">
          22 unanswered · <b>$95K recoverable</b> · ranked by lifetime value at risk, not by recency
        </div>
        <div className="row-card">
          <WorkList />
        </div>
        <div className="dc-read">
          The top of this list is where the money is — a handful of high-value customers whose relationship is recoverable if you reach them now. Answer these before the rest, route the late-delivery cases to Operations as defects, and send the batch to the Bridge to draft responses.
        </div>
      </section>

      <div className="foot-note">
        <span className="mk" />
        <p>
          A review score on its own is a vanity metric — it goes up, everyone nods, nothing changes. Tied to <b>repeat rate</b> and <b>lifetime value</b>, it becomes something useful: an early-warning signal for churn and a defect log pointing at the process that caused it. The question this room answers isn&rsquo;t &ldquo;are we liked&rdquo; — it&rsquo;s <b>&ldquo;who are we losing, why, and is it worth fixing.&rdquo;</b>
        </p>
      </div>
    </div>
  );
}

/* ───────── Root cause list ───────── */
function RootCauseList() {
  const mx = Math.max(...ROOT_CAUSES.map((c) => c.ltv));
  return (
    <>
      {ROOT_CAUSES.map((c, i) => (
        <div key={c.name} className="rc-row">
          <span className="rc-rank">{i + 1}</span>
          <div>
            <div className="rc-name">{c.name}</div>
            <div className="rc-sub">{c.sub}</div>
          </div>
          <div className="rc-bar">
            <i style={{ ["--w" as string]: `${Math.max(4, Math.round((c.ltv / mx) * 100))}%` } as React.CSSProperties} />
          </div>
          <span className="rc-tag">{c.ops}</span>
          <div className="rc-money">
            <div className="m">${(c.ltv / 1000).toFixed(0)}K</div>
            <div className="u">LTV at risk</div>
          </div>
        </div>
      ))}
    </>
  );
}

/* ───────── Worklist ───────── */
function StarRow({ stars }: { stars: number }) {
  return (
    <span className="wl-stars">
      {[1, 2, 3, 4, 5].map((i) => (
        <span key={i} className={i <= stars ? "f" : "e"}>★</span>
      ))}
    </span>
  );
}
function WorkList() {
  return (
    <>
      {AT_RISK_REVIEWS.map((w) => (
        <div key={w.name} className="wl-row">
          <div>
            <StarRow stars={w.stars} />
            <div className="wl-name">{w.name}</div>
          </div>
          <div className="wl-snip">&ldquo;{w.snip}&rdquo;</div>
          <span className="wl-cause">{w.cause}</span>
          <div className="wl-money">
            <div className="m">${(w.ltv / 1000).toFixed(1)}K</div>
            <div className="u">LTV at risk</div>
          </div>
          <span className="vpill recover">Recover</span>
        </div>
      ))}
    </>
  );
}
