"use client";

/**
 * <RatingLoyalty> — Tier-1 dual-encoding instrument.
 *
 * Gradient-coloured bars for one metric (repeat rate) plus an overlay line
 * with milled square nodes for a second metric (avg LTV on a right axis).
 * Built for the Reviews room to make the point that a star rating predicts
 * loyalty: bars and line collapse together as the rating falls. A cream
 * reading-window pins the costly-tail callout.
 *
 * Conforms to CHART-STANDARD §2:
 *   - viewBox === real pixel width via useChartSize (rule 2)
 *   - <ChartStates> wraps the SVG (rule 5)
 *   - usePrefersReducedMotion gates bar pop-in + stroke-dash line draw + nodes
 *   - No `preserveAspectRatio="none"`; no fixed-width viewBox
 *   - Props-driven; sample data exported (rule 4 — §4 data contract)
 */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface RatingPoint {
  /** 1..5 — drives the star row beneath the column. */
  stars: 1 | 2 | 3 | 4 | 5;
  /** Sample size for this rating. */
  count: number;
  /** Repeat rate as a percentage (drives bar height). */
  repeatPct: number;
  /** Avg lifetime value in USD (drives line). */
  ltv: number;
}

export interface RatingLoyaltyProps {
  data: RatingPoint[];
  state?: ChartState;
  height?: number;
  /** Y-axis upper bound for the repeat-rate bars (default 60). */
  repMax?: number;
  /** Y-axis upper bound for the LTV line on the right (default 4800). */
  ltvMax?: number;
  /** Reading-window copy. */
  readingTitle?: string;
  readingValue?: string;
  /** Show the reading window at all. */
  showReading?: boolean;
  label?: string;
}

export const sampleRatingLoyaltyData: RatingPoint[] = [
  { stars: 1, count: 4, repeatPct: 6, ltv: 480 },
  { stars: 2, count: 8, repeatPct: 9, ltv: 820 },
  { stars: 3, count: 18, repeatPct: 21, ltv: 1600 },
  { stars: 4, count: 60, repeatPct: 38, ltv: 2900 },
  { stars: 5, count: 410, repeatPct: 52, ltv: 4200 },
];

function repeatColor(r: number): [string, string] {
  if (r >= 40) return ["#33b088", "#1D9E75"];
  if (r >= 20) return ["#d4a13f", "#b88a2a"];
  return ["#e15b5b", "#d64545"];
}

export function RatingLoyalty({
  data,
  state = "ready",
  height = 430,
  repMax = 60,
  ltvMax = 4800,
  readingTitle = "THE COSTLY TAIL",
  readingValue = "1★ → 6% return",
  showReading = true,
  label = "Rating & loyalty",
}: RatingLoyaltyProps) {
  const { ref, width } = useChartSize({ min: 680, fallback: 1000 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(false);

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    setDrawn(false);
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  const W = Math.max(680, width);
  const H = height;
  const padL = 16;
  const padR = 58;
  const padT = 30;
  const padB = 64;
  const plotW = W - padL - padR;
  const plotH = H - padT - padB;
  const base = padT + plotH;

  const bw = Math.min(96, (plotW / data.length) * 0.5);
  const cxs = data.map((_, i) => padL + (i + 0.5) * (plotW / data.length));
  const yR = (v: number) => padT + (1 - v / repMax) * plotH;
  const yL = (v: number) => padT + (1 - v / ltvMax) * plotH;

  const pts = data.map((d, i) => [cxs[i], yL(d.ltv)] as [number, number]);
  const linePath = "M " + pts.map((p) => `${p[0].toFixed(1)} ${p[1].toFixed(1)}`).join(" L ");
  const lineLen = plotW + 80;

  const dx = cxs[0];
  const ry = padT + 6;
  const rx = dx - 8;
  const rw = 150;

  return (
    <div ref={ref} className="rating-wrap" style={{ width: "100%", minHeight: H }}>
      <ChartStates state={state} height={H} label={label}>
        <svg viewBox={`0 0 ${W} ${H}`} width="100%" height={H} style={{ display: "block", overflow: "visible" }}>
          <defs>
            {data.map((d, i) => {
              const [c0, c1] = repeatColor(d.repeatPct);
              return (
                <linearGradient key={i} id={`rbg${i}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0" stopColor={c0} />
                  <stop offset="1" stopColor={c1} />
                </linearGradient>
              );
            })}
          </defs>

          {/* Left axis (repeat %) */}
          {Array.from({ length: Math.floor(repMax / 20) + 1 }, (_, i) => i * 20).map((r) => {
            const yy = yR(r);
            return (
              <g key={r}>
                <line x1={padL} y1={yy} x2={W - padR} y2={yy} stroke="rgba(0,0,0,0.05)" strokeWidth={1} />
                <text x={padL + 2} y={yy - 5} fontSize={12} fill="#8a8d94" fontFamily="JetBrains Mono, monospace">
                  {r}%
                </text>
              </g>
            );
          })}

          {/* Right axis (LTV) */}
          {[0, 0.25, 0.5, 0.75, 1].map((k) => {
            const v = ltvMax * k;
            const yy = yL(v);
            return (
              <text key={k} x={W - padR + 6} y={yy + 4} fontSize={12} fill="#8a8d94" fontFamily="JetBrains Mono, monospace">
                ${(v / 1000).toFixed(1)}K
              </text>
            );
          })}

          {/* Gold corner brackets */}
          {[
            [padL, padT + 11, padL, padT, padL + 11, padT],
            [W - padR - 11, padT, W - padR, padT, W - padR, padT + 11],
            [padL, base - 11, padL, base, padL + 11, base],
            [W - padR - 11, base, W - padR, base, W - padR, base - 11],
          ].map((p, i) => (
            <path
              key={i}
              d={`M${p[0]} ${p[1]} L${p[2]} ${p[3]} L${p[4]} ${p[5]}`}
              fill="none"
              stroke="#b88a2a"
              strokeWidth={1}
              opacity={0.5}
            />
          ))}

          {/* Bars + bar values + star/count labels */}
          {data.map((d, i) => {
            const cx = cxs[i];
            const h = base - yR(d.repeatPct);
            const stars = "★".repeat(d.stars) + "☆".repeat(5 - d.stars);
            const starColor = d.stars <= 2 ? "#d64545" : d.stars === 3 ? "#b88a2a" : "#c9962f";
            const delay = 0.15 + i * 0.09;
            return (
              <g key={i}>
                <rect
                  x={cx - bw / 2}
                  y={yR(d.repeatPct)}
                  width={bw}
                  height={Math.max(h, 1)}
                  rx={4}
                  fill={`url(#rbg${i})`}
                  style={{
                    transformBox: "fill-box",
                    transformOrigin: "bottom",
                    transform: drawn ? "scaleY(1)" : "scaleY(0)",
                    transition: `transform 0.7s ${delay}s cubic-bezier(.2,.7,.3,1)`,
                  }}
                />
                <text
                  x={cx}
                  y={yR(d.repeatPct) - 9}
                  fontSize={13}
                  fill="#15171c"
                  fontFamily="Inter, sans-serif"
                  fontWeight={500}
                  textAnchor="middle"
                  style={{
                    opacity: drawn ? 1 : 0,
                    transition: `opacity 0.4s ${delay + 0.55}s`,
                  }}
                >
                  {d.repeatPct}%
                </text>
                <text x={cx} y={base + 22} fontSize={14} fill={starColor} textAnchor="middle" letterSpacing="1">
                  {stars}
                </text>
                <text x={cx} y={base + 40} fontSize={11} fill="#8a8d94" fontFamily="JetBrains Mono, monospace" textAnchor="middle">
                  {d.count} reviews
                </text>
              </g>
            );
          })}

          {/* LTV line */}
          <path
            d={linePath}
            fill="none"
            stroke="#3d4047"
            strokeWidth={2}
            strokeLinecap="round"
            strokeLinejoin="round"
            opacity={0.65}
            style={{
              strokeDasharray: lineLen,
              strokeDashoffset: drawn ? 0 : lineLen,
              transition: "stroke-dashoffset 1.4s cubic-bezier(.3,.7,.3,1)",
            }}
          />
          {pts.map((p, i) => (
            <rect
              key={i}
              x={p[0] - 3}
              y={p[1] - 3}
              width={6}
              height={6}
              rx={1.5}
              fill="#fff"
              stroke="#3d4047"
              strokeWidth={1.6}
              style={{
                opacity: drawn ? 1 : 0,
                transition: `opacity 0.4s ${0.5 + i * 0.07}s`,
              }}
            />
          ))}

          {/* Reading window */}
          {showReading && (
            <g style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.5s 1.4s" }}>
              <rect x={rx} y={ry} width={rw} height={40} rx={6} fill="#fffdf8" stroke="rgba(184,138,42,0.8)" strokeWidth={0.8} />
              <rect x={rx} y={ry} width={3} height={40} rx={1.5} fill="#d64545" />
              <text x={rx + 14} y={ry + 16} fontSize={10} fill="#b3322e" fontFamily="JetBrains Mono, monospace" letterSpacing="0.08em">
                {readingTitle}
              </text>
              <text x={rx + 14} y={ry + 32} fontSize={13} fill="#15171c" fontFamily="Inter, sans-serif" fontWeight={600}>
                {readingValue}
              </text>
            </g>
          )}

          {/* Axis legends */}
          <text x={padL} y={base + 58} fontSize={10} fill="#8a8d94" fontFamily="JetBrains Mono, monospace" letterSpacing="0.10em">
            BARS · REPEAT RATE
          </text>
          <text x={W - padR} y={base + 58} fontSize={10} fill="#8a8d94" fontFamily="JetBrains Mono, monospace" letterSpacing="0.10em" textAnchor="end">
            LINE · AVG LTV →
          </text>
        </svg>
      </ChartStates>
    </div>
  );
}
